/**  Structured transcript segment for JSON export */
export type TranscriptSegment = {
	id: string,
	text: string,
	audio_start_time: number | null,
	audio_end_time: number | null,
	duration: number | null,
	display_time: string,
	confidence: number | null,
	sequence_id: number,
	/**  Audio source: "mic" (the user) or "system" (other participants) */
	speaker?: string | null,
};

export type TranscriptionStatus = {
	chunks_in_queue: number,
	is_processing: boolean,
	last_activity_ms: number,
};

export type VocabularyEntry = {
	/**  The text the engine tends to produce (matched case-insensitively). */
	from: string,
	/**  The correct replacement (inserted verbatim). */
	to: string,
};

export type WhisperModelInfo = {
	name: string,
	path: string,
	size_mb: number,
	accuracy: string,
	speed: string,
	status: any,
	description: string,
};

/**  xAI model information returned to frontend */
export type XaiModel = {
	id: string,
	owned_by: string | null,
};

/* Tauri Specta runtime */
async function typedError<T, E>(result: Promise<T>): Promise<{ status: "ok"; data: T } | { status: "error"; error: E }> {
    try {
        return { status: "ok", data: await result };
    } catch (e) {
        if (e instanceof Error) throw e;
        return { status: "error", error: e as any };
    }
}

